// Edicion activa Vol II (Supabase UUID)
// IMPORTANT: replace with the Supabase UUID of the active edition row.
// Original Airtable recId was 'recLTGTKislECUVYG'.
return [{ json: { edicionId: 'recLTGTKislECUVYG' } }];

// MODO PRODUCCION: Enviar a alumnos reales, excluir test users
const TEST_MODE = false;

// EdicionId: intentar del workflow padre, fallback del Schedule
let edicionId;
try {
  edicionId = $('Execute Workflow Trigger').first().json.edicionId;
} catch(e) {
  edicionId = $('Simular Input').first().json.edicionId;
}
if (!edicionId) throw new Error('edicionId no recibido');

const alumnos = $('Leer Alumnos Campa\u00f1a').all().map(i => i.json);

// Emails compartidos por parejas
const sharedEmails = new Set([
  'laiarouraprat@gmail.com',
  'emiliogalvezcifuentes3@gmail.com',
  'andreajulen2019@gmail.com',
  'vallobas4ever@gmail.com',
  'chautardcynthia@gmail.com',
  'mamsalki@gmail.com'
]);

// FNV-1a hash para token de confirmacion
function makeToken(recordId) {
  const secret = 'pEv2026-xK9mP2vL7qR8nJ3w';
  const str = recordId + ':' + secret;
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16);
}

// Supabase: columns are scalar (no Airtable lookup-array wrapping).
const getField = (record, field) => {
  const val = record[field];
  return Array.isArray(val) ? val[0] : (val || '');
};

// modulos_completados is a Postgres text[]; normalize to array of strings.
const getModulos = (record) => {
  const m = record.modulos_completados;
  if (Array.isArray(m)) return m.map(x => String(x));
  if (m == null) return [];
  return String(m).split(',').map(x => x.trim()).filter(Boolean);
};

const isEnglish = (idioma) => {
  const lang = (idioma || '').toLowerCase();
  return lang.includes('ingles') || lang.includes('english') || lang.includes('eng');
};

const results = [];

for (const a of alumnos) {
  // Supabase snake_case scalar columns
  const em = getField(a, 'email');
  const nm = getField(a, 'nombre') || a['display_name'] || '';
  // Excluir TODOS los test users
  if (em.includes('andara14') || (nm+'').includes('Alumno Ficticio')) continue;

  const estado = a.estado_general;

  // Replica del filterByFormula Airtable: Finalizado solo si NO completo los 3 modulos.
  if (estado === 'Finalizado') {
    const mods = getModulos(a).join(',');
    const has1 = mods.includes('1');
    const has2 = mods.includes('2');
    const has3 = mods.includes('3');
    if (has1 && has2 && has3) continue; // completo los 3 -> excluir
  } else if (estado !== 'Rechazado') {
    continue; // solo Finalizado (parcial) o Rechazado
  }

  const email = em;
  const nombre = getField(a, 'nombre');
  const idioma = a.idioma || '';
  const isShared = sharedEmails.has(email.toLowerCase());
  const en = isEnglish(idioma);

  let mensaje, grupo;

  if (estado === 'Finalizado') {
    grupo = 'finalizado';
    const token = makeToken(a.id);
    const confirmUrl = `https://hooks.dravaautomations.com/webhook/confirmar-interes?token=${token}&edicion=${edicionId}`;

    if (en) {
      mensaje = `Public registrations for Professional Evolution Course Vol II are now open. As a student who completed modules in the previous edition, you don't need to fill out the form or submit a video again. If you're interested in participating, confirm your interest using this link: ${confirmUrl}. You'll then be able to choose the module you're interested in.`;
    } else {
      mensaje = `Las inscripciones p\u00fablicas de Professional Evolution Course Vol II ya est\u00e1n abiertas. Como alumno que completaste m\u00f3dulos en la edici\u00f3n anterior, no necesitas rellenar formulario ni enviar video de nuevo. Si te interesa participar, confirma tu inter\u00e9s en este enlace: ${confirmUrl}. Despu\u00e9s podr\u00e1s elegir el m\u00f3dulo que te interesa.`;
    }
  } else {
    grupo = 'rechazado';
    const tallyUrl = `https://tally.so/r/vGMKM0?fullname=${encodeURIComponent(nombre)}&email=${encodeURIComponent(email)}&alumnoId=${encodeURIComponent(a.id)}`;

    if (en) {
      mensaje = `Public registrations for Professional Evolution Course Vol II are now open. You can apply again by filling out the registration form at this link: ${tallyUrl}. The process includes submitting a review video so we can assess your level.`;
    } else {
      mensaje = `Las inscripciones p\u00fablicas para Professional Evolution Course Vol II est\u00e1n abiertas. Puedes aplicar de nuevo rellenando el formulario de inscripci\u00f3n en este enlace: ${tallyUrl}. El proceso incluye enviar un video de revisi\u00f3n para que podamos evaluar tu nivel.`;
    }
  }

  if (isShared) {
    mensaje += en
      ? ' Important: each student must use a unique email address for their registration.'
      : ' Importante: cada alumno debe usar un correo electr\u00f3nico \u00fanico para su inscripci\u00f3n.';
  }

  results.push({ json: {
    alumnoId: a.id, email, nombre, grupo,
    tipo: 'informacion', mensaje, estado: 'Pendiente'
  }});
}

if (results.length === 0) {
  return [{ json: { skip: true, reason: 'No alumnos reales encontrados', total: alumnos.length } }];
}

return results;
